  ('elementary-0c700c30-moex-00189', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '在作業系統的程序管理中，下列關於行程（process）和執行緒（thread）的敘述，何者最準確？', '["每個行程只能包含一個執行緒", "執行緒之間不共享記憶體資源", "行程是作業系統進行資源分配的基本單位", "多執行緒不會增加系統的並行處理能力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:30+00:00", "source_pdf_sha1": "a665a08a155a", "answer_pdf_sha1": "a86b5ed00344", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
