  ('elementary-0c700c30-moex-00191', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '假設籃球選手所屬球隊和球賽得分的二個資料表分別為：選手(識別碼, 姓名, 球隊)與球賽(識別碼, 場次, 得分)，下列SQL查詢要找出那些球隊有從未上場過的球員： SELECTDISTINCT 球隊 FROM 選手 P WHERE________( SELECT* FROM 球賽 G WHEREG.識別碼 =P.識別碼 ); 請問空格處要填入那個運算子？', '["EXISTS", "NOTEXISTS", "IN", "NOTIN"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:30+00:00", "source_pdf_sha1": "a665a08a155a", "answer_pdf_sha1": "a86b5ed00344", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00192', 'elementary-0c700c30', 'elementary-0c700c30-moex-114-e8c1e471', 'sub-elementary-0c700c30-04', NULL, 'single_choice', '電子商務的B2C（企業對消費者）模式通常有那種特徵？', '["主要針對企業之間的交易，涉及大量商品進出口", "面向終端消費者，通常以網頁或應用程式形式提供服務", "著重於線下物流管理，不依賴網路平台", "通常只支持電子郵件形式的訂單交易"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:30+00:00", "source_pdf_sha1": "a665a08a155a", "answer_pdf_sha1": "a86b5ed00344", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "512", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "資料處理大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00193', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '假定甲國的生產可能曲線往右上方擴增，下列何者可能是甲國生產可能性曲線發生變化的原因？', '["貧富差距縮小", "經濟出現停滯", "失業率上升", "生產技術進步"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00194', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '經濟制度是指政府介入人民經濟生活的方式與程度，下列有關「市場經濟制度」的敘述，何者錯誤？', '["政府保障人民的消費自由", "政府尊重市場的價格機能", "政府讓個人依自利做決策", "政府將生產工具收歸國有"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00195', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '某列車與一輛從斜坡上跌落到鐵軌上的工程車相撞後出軌，造成人員傷亡慘重。事故發生後，某位脫困乘 客因被其他人拍到站在事故旁的邊坡，而被媒體誤報為「偷偷施工又見死不救的工人」，導致該名乘客被 誤解的網路鄉民肉搜與圍剿。從媒體識讀的角度檢視，何者最適合用來描述前述媒體報導所引發的現象？', '["媒體未善盡查證責任，報導內容出現不實的訊息", "媒體為搶收視率，以煽情的內容渲染大眾的情緒", "媒體形塑勞工負面刻板印象，加劇民眾對勞工的歧視", "媒體報導檢察官尚在調查的訊息，違反偵查不公開原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00196', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '政府利用租稅課徵與財政支出的手段，可以發揮一定的經濟效果，下列有關政府財政收支的敘述，何者 正確？', '["降低進口關稅可保護本國就業機會，增加消費者福利", "提高營業稅與貨物稅稅率，可縮小社會財富分配差距", "降低土地增值稅稅率，助長土地投機不利租稅公平性", "擴大公共工程的投資性支出，會增加總體經濟的供給，可刺激經濟景氣的復甦"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL),
  ('elementary-0c700c30-moex-00197', 'elementary-0c700c30', 'elementary-0c700c30-moex-113-b3f42868', 'sub-elementary-0c700c30-01', NULL, 'single_choice', '某報報導：「疫情升溫，清境、日月潭及溪頭等地的旅館業表示，退房率大約一至二成，且訂房也沒像往 年熱絡，價格正往下修正……」其他條件不變下，試問前述報導最符合下列何種現象？', '["需求曲線不動，需求量（quantitydemanded）減少", "需求曲線不動，需求量（quantitydemanded）增加", "需求曲線左移，需求量（quantitydemanded）減少", "需求曲線左移，需求量（quantitydemanded）增加"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:31+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "509", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "統計"}'::jsonb, NULL)
